import numpy as np

class CreditMetricsCalculator:
    """
    Calculate comprehensive credit scoring metrics.
    """

    def __init__(self, y_true, y_prob):
        self.y_true = np.array(y_true)
        self.y_prob = np.array(y_prob)
        self.n = len(y_true)
        self.n_pos = np.sum(y_true)
        self.n_neg = self.n - self.n_pos

    def auc(self):
        """Calculate ROC-AUC using Mann-Whitney U statistic."""
        pos_probs = self.y_prob[self.y_true == 1]
        neg_probs = self.y_prob[self.y_true == 0]

        if len(pos_probs) == 0 or len(neg_probs) == 0:
            return 0.5

        # Count pairs where positive has higher probability
        u_stat = 0
        for p in pos_probs:
            u_stat += np.sum(neg_probs < p) + 0.5 * np.sum(neg_probs == p)

        return u_stat / (len(pos_probs) * len(neg_probs))

    def gini(self):
        """Calculate Gini coefficient."""
        return 2 * self.auc() - 1

    def ks_statistic(self):
        """Calculate KS statistic."""
        if self.n_pos == 0 or self.n_neg == 0:
            return 0

        sorted_idx = np.argsort(self.y_prob)[::-1]
        y_sorted = self.y_true[sorted_idx]

        cum_pos = np.cumsum(y_sorted) / self.n_pos
        cum_neg = np.cumsum(1 - y_sorted) / self.n_neg

        return np.max(np.abs(cum_pos - cum_neg))

    def brier_score(self):
        """Calculate Brier score."""
        return np.mean((self.y_prob - self.y_true)**2)

    def lift_at_percentile(self, percentile=10):
        """Calculate lift at top percentile."""
        n_top = max(1, int(self.n * percentile / 100))
        top_idx = np.argsort(self.y_prob)[-n_top:]

        top_rate = np.mean(self.y_true[top_idx])
        base_rate = np.mean(self.y_true)

        if base_rate == 0:
            return 0
        return top_rate / base_rate

    def precision_at_k(self, k):
        """Precision at top k predictions."""
        top_idx = np.argsort(self.y_prob)[-k:]
        return np.mean(self.y_true[top_idx])

    def recall_at_k(self, k):
        """Recall at top k predictions."""
        if self.n_pos == 0:
            return 0
        top_idx = np.argsort(self.y_prob)[-k:]
        return np.sum(self.y_true[top_idx]) / self.n_pos

    def log_loss(self):
        """Calculate log loss."""
        eps = 1e-15
        y_prob_clipped = np.clip(self.y_prob, eps, 1 - eps)
        return -np.mean(self.y_true * np.log(y_prob_clipped) + 
                       (1 - self.y_true) * np.log(1 - y_prob_clipped))

    def calibration_error(self, n_bins=10):
        """Calculate expected calibration error."""
        bins = np.linspace(0, 1, n_bins + 1)
        ece = 0

        for i in range(n_bins):
            mask = (self.y_prob >= bins[i]) & (self.y_prob < bins[i+1])
            if mask.sum() > 0:
                avg_conf = np.mean(self.y_prob[mask])
                avg_acc = np.mean(self.y_true[mask])
                ece += mask.sum() * np.abs(avg_acc - avg_conf)

        return ece / self.n

    def full_report(self):
        """Generate comprehensive report."""
        return {
            'n_samples': self.n,
            'n_positives': self.n_pos,
            'base_rate': self.n_pos / self.n,
            'discrimination': {
                'auc': self.auc(),
                'gini': self.gini(),
                'ks': self.ks_statistic()
            },
            'calibration': {
                'brier_score': self.brier_score(),
                'log_loss': self.log_loss(),
                'calibration_error': self.calibration_error()
            },
            'lift': {
                'lift_10': self.lift_at_percentile(10),
                'lift_20': self.lift_at_percentile(20),
                'lift_50': self.lift_at_percentile(50)
            },
            'model_quality': self._assess_quality()
        }

    def _assess_quality(self):
        """Assess overall model quality."""
        auc = self.auc()
        ks = self.ks_statistic()

        if auc > 0.8 and ks > 0.4:
            return 'Excellent'
        elif auc > 0.7 and ks > 0.3:
            return 'Good'
        elif auc > 0.6 and ks > 0.2:
            return 'Fair'
        else:
            return 'Poor'

# Test
