print("=" * 50)

np.random.seed(42)
y_true = np.random.binomial(1, 0.15, 1000)
y_prob = np.clip(y_true * 0.4 + np.random.beta(2, 5, 1000), 0, 1)

calc = CreditMetricsCalculator(y_true, y_prob)
report = calc.full_report()

print(f"\nSamples: {report['n_samples']}, Positives: {report['n_positives']}")
print(f"Base rate: {report['base_rate']:.2%}")

print("\nDiscrimination Metrics:")
for k, v in report['discrimination'].items():
    print(f"  {k.upper()}: {v:.4f}")

print("\nCalibration Metrics:")
for k, v in report['calibration'].items():
    print(f"  {k}: {v:.4f}")

print("\nLift Metrics:")
for k, v in report['lift'].items():
    print(f"  {k}: {v:.2f}x")

print(f"\nModel Quality: {report['model_quality']}")

import numpy as np
from scipy import stats

class StratifiedCrossValidator:
    """
    Stratified cross-validation for credit models.
    """

    def __init__(self, n_folds=5, shuffle=True, random_state=None):
        self.n_folds = n_folds
        self.shuffle = shuffle
        self.random_state = random_state
        if random_state is not None:
            np.random.seed(random_state)

    def split(self, X, y):
        """Generate stratified train/test indices."""
        y = np.array(y)
        pos_idx = np.where(y == 1)[0]
        neg_idx = np.where(y == 0)[0]

        if self.shuffle:
            np.random.shuffle(pos_idx)
            np.random.shuffle(neg_idx)

        # Split each class into folds
        pos_folds = np.array_split(pos_idx, self.n_folds)
        neg_folds = np.array_split(neg_idx, self.n_folds)

        for i in range(self.n_folds):
            test_idx = np.concatenate([pos_folds[i], neg_folds[i]])
            train_idx = np.concatenate([
                np.concatenate([pos_folds[j] for j in range(self.n_folds) if j != i]),
                np.concatenate([neg_folds[j] for j in range(self.n_folds) if j != i])
            ])
            yield train_idx, test_idx

    def _compute_metric(self, y_true, y_pred, y_prob, metric):
        """Compute a single metric."""
        if metric == 'accuracy':
            return np.mean(y_pred == y_true)
        elif metric == 'auc':
            pos_probs = y_prob[y_true == 1]
            neg_probs = y_prob[y_true == 0]
            if len(pos_probs) == 0 or len(neg_probs) == 0:
                return 0.5
            u = 0
            for p in pos_probs:
                u += np.sum(neg_probs < p) + 0.5 * np.sum(neg_probs == p)
            return u / (len(pos_probs) * len(neg_probs))
        elif metric == 'precision':
            tp = np.sum((y_pred == 1) & (y_true == 1))
            fp = np.sum((y_pred == 1) & (y_true == 0))
            return tp / (tp + fp) if (tp + fp) > 0 else 0
        elif metric == 'recall':
            tp = np.sum((y_pred == 1) & (y_true == 1))
            fn = np.sum((y_pred == 0) & (y_true == 1))
            return tp / (tp + fn) if (tp + fn) > 0 else 0
        elif metric == 'f1':
            prec = self._compute_metric(y_true, y_pred, y_prob, 'precision')
            rec = self._compute_metric(y_true, y_pred, y_prob, 'recall')
            return 2 * prec * rec / (prec + rec) if (prec + rec) > 0 else 0
        else:
            return np.mean(y_pred == y_true)

    def cross_val_score(self, model_class, X, y, metric='accuracy', **model_kwargs):
        """Run cross-validation and return scores."""
        X, y = np.array(X), np.array(y)
        scores = []

        for train_idx, test_idx in self.split(X, y):
            model = model_class(**model_kwargs)
            model.fit(X[train_idx], y[train_idx])

            y_pred = model.predict(X[test_idx])
            y_prob = model.predict_proba(X[test_idx]) if hasattr(model, 'predict_proba') else y_pred

            score = self._compute_metric(y[test_idx], y_pred, y_prob, metric)
            scores.append(score)

        return np.array(scores)

    def confidence_interval(self, scores, confidence=0.95):
        """Calculate confidence interval for scores."""
        n = len(scores)
        mean = np.mean(scores)
        se = np.std(scores, ddof=1) / np.sqrt(n)

        # t-distribution for small samples
        t_value = stats.t.ppf((1 + confidence) / 2, n - 1)
        margin = t_value * se

        return (mean - margin, mean + margin)

    def full_cv_report(self, model_class, X, y, metrics=['accuracy', 'auc'], **model_kwargs):
        """Generate full CV report with multiple metrics."""
        X, y = np.array(X), np.array(y)

        results = {
            'n_samples': len(y),
            'n_folds': self.n_folds,
            'class_distribution': {
                'n_positive': int(np.sum(y)),
                'n_negative': int(np.sum(y == 0)),
                'positive_rate': float(np.mean(y))
            },
            'metrics': {}
        }

        for metric in metrics:
            scores = self.cross_val_score(model_class, X, y, metric, **model_kwargs)
            ci_low, ci_high = self.confidence_interval(scores)

            results['metrics'][metric] = {
                'scores': scores.tolist(),
                'mean': float(np.mean(scores)),
                'std': float(np.std(scores)),
                'min': float(np.min(scores)),
                'max': float(np.max(scores)),
                'ci_95': (float(ci_low), float(ci_high))
            }

        return results

# Test
