class SimpleModel:
    def __init__(self):
        self.w = None
    def fit(self, X, y):
        self.w = np.mean(X[y == 1], axis=0) - np.mean(X[y == 0], axis=0)
        return self
    def predict(self, X):
        return (X @ self.w > 0).astype(int)
    def predict_proba(self, X):
        scores = X @ self.w
        return 1 / (1 + np.exp(-scores))

np.random.seed(42)
X = np.random.randn(200, 4)
y = (X[:, 0] + X[:, 1] > 0).astype(int)

cv = StratifiedCrossValidator(n_folds=5, random_state=42)
report = cv.full_cv_report(SimpleModel, X, y, metrics=['accuracy', 'auc', 'f1'])

print(f"\nSamples: {report['n_samples']}, Folds: {report['n_folds']}")
print(f"Positive rate: {report['class_distribution']['positive_rate']:.2%}")

for metric, data in report['metrics'].items():
    print(f"\n{metric.upper()}:")
    print(f"  Mean: {data['mean']:.4f} ± {data['std']:.4f}")
    print(f"  95% CI: [{data['ci_95'][0]:.4f}, {data['ci_95'][1]:.4f}]")
    print(f"  Range: [{data['min']:.4f}, {data['max']:.4f}]")

import numpy as np

class FairnessAnalyzer:
    """
    Analyze fairness of credit scoring model.
    """

    def __init__(self, y_true, y_prob, protected_attrs):
        self.y_true = np.array(y_true)
        self.y_prob = np.array(y_prob)
        self.protected = {k: np.array(v) for k, v in protected_attrs.items()}
        self.n = len(y_true)

    def _get_groups(self, attr_name):
        """Get unique groups for an attribute."""
        return np.unique(self.protected[attr_name])

    def demographic_parity(self, attr_name, threshold=0.5):
        """Check demographic parity for an attribute."""
        attr = self.protected[attr_name]
        groups = self._get_groups(attr_name)
        y_pred = (self.y_prob >= threshold).astype(int)

        rates = {}
        for group in groups:
            mask = attr == group
            rates[str(group)] = float(np.mean(y_pred[mask]))

        max_diff = max(rates.values()) - min(rates.values())

        return {
            'metric': 'demographic_parity',
            'attribute': attr_name,
            'approval_rates': rates,
            'max_difference': max_diff,
            'pass': max_diff < 0.1
        }

    def equal_opportunity(self, attr_name, threshold=0.5):
        """Check equal opportunity (TPR equality)."""
        attr = self.protected[attr_name]
        groups = self._get_groups(attr_name)
        y_pred = (self.y_prob >= threshold).astype(int)

        tprs = {}
        for group in groups:
            mask = (attr == group) & (self.y_true == 1)
            if mask.sum() > 0:
                tprs[str(group)] = float(np.mean(y_pred[mask]))
            else:
                tprs[str(group)] = None

        valid_tprs = [v for v in tprs.values() if v is not None]
        max_diff = max(valid_tprs) - min(valid_tprs) if len(valid_tprs) > 1 else 0

        return {
            'metric': 'equal_opportunity',
            'attribute': attr_name,
            'true_positive_rates': tprs,
            'max_difference': max_diff,
            'pass': max_diff < 0.1
        }

    def equalized_odds(self, attr_name, threshold=0.5):
        """Check equalized odds (TPR and FPR equality)."""
        attr = self.protected[attr_name]
        groups = self._get_groups(attr_name)
        y_pred = (self.y_prob >= threshold).astype(int)

        tprs, fprs = {}, {}
        for group in groups:
            # TPR
            pos_mask = (attr == group) & (self.y_true == 1)
            if pos_mask.sum() > 0:
                tprs[str(group)] = float(np.mean(y_pred[pos_mask]))
            else:
                tprs[str(group)] = None

            # FPR
            neg_mask = (attr == group) & (self.y_true == 0)
            if neg_mask.sum() > 0:
                fprs[str(group)] = float(np.mean(y_pred[neg_mask]))
            else:
                fprs[str(group)] = None

        valid_tprs = [v for v in tprs.values() if v is not None]
        valid_fprs = [v for v in fprs.values() if v is not None]

        tpr_diff = max(valid_tprs) - min(valid_tprs) if len(valid_tprs) > 1 else 0
        fpr_diff = max(valid_fprs) - min(valid_fprs) if len(valid_fprs) > 1 else 0

        return {
            'metric': 'equalized_odds',
            'attribute': attr_name,
            'true_positive_rates': tprs,
            'false_positive_rates': fprs,
            'tpr_difference': tpr_diff,
            'fpr_difference': fpr_diff,
            'pass': tpr_diff < 0.1 and fpr_diff < 0.1
        }

    def disparate_impact(self, attr_name, threshold=0.5):
        """Calculate disparate impact ratio."""
        dp = self.demographic_parity(attr_name, threshold)
        rates = list(dp['approval_rates'].values())

        if min(rates) == 0:
            ratio = 0
        else:
            ratio = min(rates) / max(rates)

        return {
            'metric': 'disparate_impact',
            'attribute': attr_name,
            'ratio': ratio,
            'four_fifths_rule': ratio >= 0.8,
            'pass': ratio >= 0.8
        }

    def calibration_by_group(self, attr_name, n_bins=5):
        """Check calibration by group."""
        attr = self.protected[attr_name]
        groups = self._get_groups(attr_name)

        calibration = {}
        for group in groups:
            mask = attr == group
            probs = self.y_prob[mask]
            labels = self.y_true[mask]

            # Bin predictions
            bins = np.linspace(0, 1, n_bins + 1)
            bin_means = []
            bin_actuals = []

            for i in range(n_bins):
                bin_mask = (probs >= bins[i]) & (probs < bins[i+1])
                if bin_mask.sum() > 0:
                    bin_means.append(float(np.mean(probs[bin_mask])))
                    bin_actuals.append(float(np.mean(labels[bin_mask])))

            calibration[str(group)] = {
                'predicted': bin_means,
                'actual': bin_actuals
            }

        return {
            'metric': 'calibration_by_group',
            'attribute': attr_name,
            'calibration': calibration
        }

    def full_fairness_audit(self, threshold=0.5):
        """Complete fairness audit across all attributes."""
        audit = {
            'threshold': threshold,
            'n_samples': self.n,
            'overall_positive_rate': float(np.mean(self.y_true)),
            'attributes': {}
        }

        for attr_name in self.protected.keys():
            audit['attributes'][attr_name] = {
                'demographic_parity': self.demographic_parity(attr_name, threshold),
                'equal_opportunity': self.equal_opportunity(attr_name, threshold),
                'equalized_odds': self.equalized_odds(attr_name, threshold),
                'disparate_impact': self.disparate_impact(attr_name, threshold)
            }

        # Overall assessment
        all_pass = all(
            result['pass']
            for attr_results in audit['attributes'].values()
            for result in attr_results.values()
        )

        audit['overall_assessment'] = 'PASS' if all_pass else 'REVIEW REQUIRED'

        return audit

# Test
print("Fairness Analyzer")
print("=" * 50)

np.random.seed(42)
n = 1000
y_true = np.random.binomial(1, 0.15, n)
y_prob = np.clip(y_true * 0.4 + np.random.beta(2, 5, n), 0, 1)

protected = {
    'age_group': np.random.choice(['young', 'middle', 'senior'], n),
    'gender': np.random.choice(['M', 'F'], n)
}

analyzer = FairnessAnalyzer(y_true, y_prob, protected)
audit = analyzer.full_fairness_audit()

print(f"\nSamples: {audit['n_samples']}")
print(f"Overall positive rate: {audit['overall_positive_rate']:.2%}")

for attr_name, results in audit['attributes'].items():
    print(f"\n{attr_name.upper()}:")
    di = results['disparate_impact']
    print(f"  Disparate Impact Ratio: {di['ratio']:.3f} ({'PASS' if di['pass'] else 'FAIL'})")
    dp = results['demographic_parity']
    print(f"  Demographic Parity Diff: {dp['max_difference']:.3f}")

print(f"\nOverall Assessment: {audit['overall_assessment']}")
